const body = $input.first().json.body;
const headers = $input.first().json.headers;

// 1. Validate secret token
const secret = headers['x-curiel-secret'];
if (!secret || secret !== $env.CURIEL_SECRET_TOKEN) {
  return [{ json: { valid: false, error: 'INVALID_SECRET', message: 'Token de seguridad invalido' } }];
}

// 2. Validate payload structure
const required = ['type', 'inspectionId', 'inspectionStatus', 'recipient'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  return [{ json: { valid: false, error: 'MISSING_FIELDS', message: `Campos requeridos faltantes: ${missing.join(', ')}` } }];
}

if (!body.recipient?.email || !body.recipient?.fullName) {
  return [{ json: { valid: false, error: 'INVALID_RECIPIENT', message: 'Recipient debe tener email y fullName' } }];
}

// 3. Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.recipient.email)) {
  return [{ json: { valid: false, error: 'INVALID_EMAIL', message: `Email invalido: ${body.recipient.email}` } }];
}

// 4. Normalize status
const validStatuses = ['pendiente', 'en_proceso', 'lista_revision', 'finalizada', 'cancelada', 'reprogramada'];
if (!validStatuses.includes(body.inspectionStatus)) {
  return [{ json: { valid: false, error: 'INVALID_STATUS', message: `Status invalido: ${body.inspectionStatus}` } }];
}

// 5. Check for duplicate webhook (idempotency)
const dedupKey = `${body.inspectionId}-${body.inspectionStatus}-${body.recipient.id}`;

return [{ json: { ...body, valid: true, dedupKey } }];

const data = $input.first().json;
if (data.valid === false) {
  throw new Error(`Validation failed [${data.error}]: ${data.message}`);
}
return $input.all();

const status = $input.first().json.inspectionStatus;
const statusConfig = {
  pendiente: {
    label: 'Pendiente',
    color: '#f59e0b',
    bgColor: '#fef3c7',
    icon: '&#128337;',
    inspectorMsg: 'Una inspeccion ha sido asignada y esta pendiente de inicio.',
    clientMsg: 'Su inspeccion ha sido programada y esta pendiente.',
    urgency: 'normal'
  },
  en_proceso: {
    label: 'En proceso',
    color: '#3b82f6',
    bgColor: '#dbeafe',
    icon: '&#9654;',
    inspectorMsg: 'La inspeccion ha sido iniciada. Puede comenzar el trabajo de campo.',
    clientMsg: 'Su inspeccion esta en proceso.',
    urgency: 'normal'
  },
  lista_revision: {
    label: 'Lista para revision',
    color: '#8b5cf6',
    bgColor: '#ede9fe',
    icon: '&#128269;',
    inspectorMsg: 'El informe esta listo para revision del supervisor.',
    clientMsg: 'Su informe esta siendo revisado por nuestro equipo.',
    urgency: 'high'
  },
  finalizada: {
    label: 'Finalizada',
    color: '#10b981',
    bgColor: '#d1fae5',
    icon: '&#9989;',
    inspectorMsg: 'La inspeccion ha sido finalizada y aprobada.',
    clientMsg: 'Su inspeccion ha sido completada exitosamente.',
    urgency: 'normal'
  },
  cancelada: {
    label: 'Cancelada',
    color: '#ef4444',
    bgColor: '#fee2e2',
    icon: '&#10060;',
    inspectorMsg: 'La inspeccion ha sido cancelada.',
    clientMsg: 'Su inspeccion ha sido cancelada.',
    urgency: 'high'
  },
  reprogramada: {
    label: 'Reprogramada',
    color: '#f97316',
    bgColor: '#ffedd5',
    icon: '&#128259;',
    inspectorMsg: 'La inspeccion ha sido reprogramada. Verifique la nueva fecha.',
    clientMsg: 'Su inspeccion ha sido reprogramada.',
    urgency: 'high'
  }
};
const config = statusConfig[status] || statusConfig.pendiente;
const data = $input.first().json;
const inspectionId = data.inspectionId;
const frontendUrl = $env.FRONTEND_URL || 'https://aimachristian-curielapp.ajcxjb.easypanel.host';
const inspectionUrl = `${frontendUrl}/inspections/${inspectionId}`;
const reason = data.reasonLabel || data.reasonCode || '';
const comment = data.comment || '';
let reasonBlock = '';
if (reason || comment) {
  reasonBlock = `<div style='background:#f9fafb;border-left:4px solid ${config.color};padding:12px 16px;margin:16px 0;border-radius:0 8px 8px 0'><p style='color:#374151;font-size:14px;margin:0'>${reason ? `<strong>Motivo:</strong> ${reason}` : ''}${reason && comment ? '<br>' : ''}${comment ? `<strong>Comentario:</strong> ${comment}` : ''}</p></div>`;
}
return [{ json: { ...data, config, inspectionUrl, reasonBlock } }];

const data = $input.first().json;
const status = data.inspectionStatus;
const config = data.config;
const inspectionId = data.inspectionId;
const recipient = data.recipient;
const inspectionUrl = data.inspectionUrl;
const reasonBlock = data.reasonBlock;
const year = new Date().getFullYear();
const html = `
<div style='font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:0'>
  <div style='background:${config.bgColor};border-radius:16px 16px 0 0;padding:32px;text-align:center'>
    <span style='font-size:48px'>${config.icon}</span>
    <h1 style='color:${config.color};font-size:24px;margin:12px 0 4px;font-family:Georgia,serif'>${config.label}</h1>
    <p style='color:#6b7280;font-size:13px;margin:0'>Inspeccion #${inspectionId.substring(0, 8)}</p>
  </div>
  <div style='background:#ffffff;padding:32px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 16px 16px'>
    <p style='color:#374151;font-size:15px;line-height:1.7;margin:0 0 16px'>Hola <strong>${recipient.fullName}</strong>,</p>
    <p style='color:#374151;font-size:15px;line-height:1.7;margin:0 0 16px'>${data.notifyClient ? config.clientMsg : config.inspectorMsg}</p>
    ${reasonBlock}
    <div style='text-align:center;margin:28px 0'>
      <a href='${inspectionUrl}' style='display:inline-block;background:#17324a;color:#ffffff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:15px;font-weight:600'>Ver inspeccion</a>
    </div>
    <hr style='border:none;border-top:1px solid #e5e7eb;margin:24px 0'>
    <p style='color:#9ca3af;font-size:12px;text-align:center;margin:0'>CURIEL Inspecciones &middot; Sistema tecnico de gestion</p>
  </div>
</div>`;
return [{ json: { to: recipient.email, subject: `[CURIEL] ${config.label} - Inspeccion ${inspectionId.substring(0, 8)}`, html, status, config } }];

const data = $json.data;
const config = data.config;
const inspectionUrl = data.inspectionUrl;
const reasonBlock = data.reasonBlock;
const year = new Date().getFullYear();
const clientName = data.recipient.fullName.split(' ')[0] || data.recipient.fullName;
const html = `
<div style='font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:0'>
  <div style='background:${config.bgColor};border-radius:16px 16px 0 0;padding:32px;text-align:center'>
    <span style='font-size:48px'>${config.icon}</span>
    <h1 style='color:${config.color};font-size:22px;margin:12px 0 4px;font-family:Georgia,serif'>${config.label}</h1>
  </div>
  <div style='background:#ffffff;padding:32px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 16px 16px'>
    <p style='color:#374151;font-size:15px;line-height:1.7;margin:0 0 16px'>Estimado(a) <strong>${clientName}</strong>,</p>
    <p style='color:#374151;font-size:15px;line-height:1.7;margin:0 0 16px'>${config.clientMsg}</p>
    ${reasonBlock}
    <div style='background:#f0f9ff;border-radius:10px;padding:16px;margin:20px 0'>
      <p style='color:#1e40af;font-size:13px;margin:0;text-align:center'>Si tiene alguna pregunta, contacte a su asesor o responda este correo.</p>
    </div>
    <hr style='border:none;border-top:1px solid #e5e7eb;margin:24px 0'>
    <p style='color:#9ca3af;font-size:12px;text-align:center;margin:0'>CURIEL Inspecciones &middot; &copy; ${year}</p>
  </div>
</div>`;
return [{ json: { to: data.recipient.email, subject: `[CURIEL] Actualizacion de su inspeccion`, html } }];

const status = $input.first().json.status;
const isUrgent = ['cancelada', 'reprogramada', 'lista_revision'].includes(status);

if (!isUrgent) {
  return [{ json: { shouldAlert: false } }];
}

return [{ json: { shouldAlert: true, status } }];

const inspectorEmail = $('Send Inspector Email').first();
const clientEmail = $('Notify Client?').first().json.shouldAlert ? $('Send Client Email').first() : null;
const adminAlert = $('Is Urgent?').first().json.shouldAlert ? $('Send Admin Alert').first() : null;

const results = {
  inspector: { sent: !inspectorEmail.json.error, error: inspectorEmail.json.error || null },
  client: clientEmail ? { sent: !clientEmail.json.error, error: clientEmail.json.error || null } : { sent: false, skipped: true },
  adminAlert: adminAlert ? { sent: !adminAlert.json.error, error: adminAlert.json.error || null } : { sent: false, skipped: true }
};

return [{ json: { success: true, summary: results, timestamp: new Date().toISOString() } }];
